import{_ as e,c as t,o as r,a1 as l}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"進階功能: 格式化原理 | opencode-md-table-formatter","description":"深入了解 opencode-md-table-formatter 的格式化原理。掌握隱藏模式、表格規範和對齊方式，全面理解外掛工作原理。","frontmatter":{"title":"進階功能: 格式化原理 | opencode-md-table-formatter","subtitle":"進階功能: 格式化原理","sidebarTitle":"理解工作原理","order":2,"description":"深入了解 opencode-md-table-formatter 的格式化原理。掌握隱藏模式、表格規範和對齊方式，全面理解外掛工作原理。","prerequisite":["start-getting-started","start-features"],"tags":["進階","原理","規範"]},"headers":[],"relativePath":"zh-tw/franlol/opencode-md-table-formatter/advanced/index.md","filePath":"zh-tw/franlol/opencode-md-table-formatter/advanced/index.md"}'),o={name:"zh-tw/franlol/opencode-md-table-formatter/advanced/index.md"};function i(n,a,s,d,c,h){return r(),t("div",null,[...a[0]||(a[0]=[l('<h1 id="進階功能-深入了解-markdown-表格格式化的技術細節" tabindex="-1">進階功能：深入了解 Markdown 表格格式化的技術細節 <a class="header-anchor" href="#進階功能-深入了解-markdown-表格格式化的技術細節" aria-label="Permalink to &quot;進階功能：深入了解 Markdown 表格格式化的技術細節&quot;">​</a></h1><h2 id="章節概述" tabindex="-1">章節概述 <a class="header-anchor" href="#章節概述" aria-label="Permalink to &quot;章節概述&quot;">​</a></h2><p>本章節深入探討 Markdown 表格格式化的技術細節，包括 OpenCode 隱藏模式的工作原理、有效表格的結構規範以及對齊方式的詳細說明。透過學習這些內容，你將全面理解外掛如何處理表格格式化，以及如何避免常見錯誤。</p><h2 id="學習路徑" tabindex="-1">學習路徑 <a class="header-anchor" href="#學習路徑" aria-label="Permalink to &quot;學習路徑&quot;">​</a></h2><p>建議按以下順序學習本章節的內容：</p><div class="info custom-block"><p class="custom-block-title">學習路徑</p><ol><li><strong>隱藏模式原理</strong> → 理解為什麼需要特殊處理 OpenCode 的隱藏模式</li><li><strong>表格規範</strong> → 掌握什麼樣的表格才能被正確格式化</li><li><strong>對齊方式詳解</strong> → 學習如何控制表格的對齊和美觀度</li></ol></div><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><p>在開始本章節之前，請確保你已經：</p><ul><li>[x] 完成了 <a href="./../start/getting-started/">一分鐘上手</a>，成功安裝並設定了外掛</li><li>[x] 閱讀了 <a href="./../start/features/">功能全覽</a>，了解了外掛的基本功能</li></ul><div class="warning custom-block"><p class="custom-block-title">重要提示</p><p>如果你還沒有完成基礎學習，建議先回到 <a href="./../start/getting-started/">上手指南</a> 開始。</p></div><h2 id="課程導航" tabindex="-1">課程導航 <a class="header-anchor" href="#課程導航" aria-label="Permalink to &quot;課程導航&quot;">​</a></h2><h3 id="隱藏模式原理" tabindex="-1"><a href="./concealment-mode/">隱藏模式原理</a> <a class="header-anchor" href="#隱藏模式原理" aria-label="Permalink to &quot;[隱藏模式原理](./concealment-mode/)&quot;">​</a></h3><p>理解 OpenCode 隱藏模式的工作原理，以及外掛如何正確計算顯示寬度。你將學到：</p><ul><li>什麼是隱藏模式，為什麼需要特殊處理</li><li>Markdown 符號剝離演算法如何工作</li><li><code>Bun.stringWidth()</code> 在寬度計算中的作用</li></ul><p><strong>預計耗時</strong>：8 分鐘 | <strong>難度</strong>：中等 | <strong>前置</strong>：功能全覽</p><hr><h3 id="表格規範" tabindex="-1"><a href="./table-spec/">表格規範</a> <a class="header-anchor" href="#表格規範" aria-label="Permalink to &quot;[表格規範](./table-spec/)&quot;">​</a></h3><p>掌握有效 Markdown 表格的結構要求，避免「無效表格」錯誤。你將學到：</p><ul><li>什麼樣的表格結構是有效的</li><li>分隔行的作用和格式要求</li><li>欄數一致性檢查的原理</li><li>如何快速識別表格結構問題</li></ul><p><strong>預計耗時</strong>：6 分鐘 | <strong>難度</strong>：入門 | <strong>前置</strong>：隱藏模式原理</p><hr><h3 id="對齊方式詳解" tabindex="-1"><a href="./alignment/">對齊方式詳解</a> <a class="header-anchor" href="#對齊方式詳解" aria-label="Permalink to &quot;[對齊方式詳解](./alignment/)&quot;">​</a></h3><p>掌握三種對齊方式的語法和效果，讓表格更美觀。你將學到：</p><ul><li>左對齊、置中對齊、右對齊的語法</li><li>如何在分隔行指定對齊方式</li><li>儲存格內容填充演算法</li><li>對齊與顯示寬度的關係</li></ul><p><strong>預計耗時</strong>：10 分鐘 | <strong>難度</strong>：中等 | <strong>前置</strong>：表格規範</p><hr><h2 id="本章節小結" tabindex="-1">本章節小結 <a class="header-anchor" href="#本章節小結" aria-label="Permalink to &quot;本章節小結&quot;">​</a></h2><p>完成本章節後，你將：</p><ul><li>✅ 理解 OpenCode 隱藏模式的工作原理</li><li>✅ 掌握有效表格的結構要求</li><li>✅ 能夠識別和修復無效表格</li><li>✅ 熟練使用三種對齊方式</li><li>✅ 理解外掛內部的技術實作細節</li></ul><h2 id="下一步指引" tabindex="-1">下一步指引 <a class="header-anchor" href="#下一步指引" aria-label="Permalink to &quot;下一步指引&quot;">​</a></h2><p>完成本章節後，你可以：</p><ol><li><strong>解決實際問題</strong> → 學習 <a href="./../../faq/troubleshooting/">常見問題</a>，快速定位和解決問題</li><li><strong>了解技術邊界</strong> → 閱讀 <a href="./../../appendix/limitations/">已知限制</a>，了解外掛的適用場景</li><li><strong>深入了解實作</strong> → 查看 <a href="./../../appendix/tech-details/">技術細節</a>，了解快取機制與效能優化</li></ol><hr><div class="tip custom-block"><p class="custom-block-title">實用建議</p><p>如果你想快速解決表格格式化問題，可以先閱讀本章節的 <a href="./table-spec/">表格規範</a>，它包含了最常見的無效表格案例。</p></div>',34)])])}const u=e(o,[["render",i]]);export{m as __pageData,u as default};
